1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two adjacent live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should create a new live cell at a dead position with exactly 3 live neighbors (reproduction)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it.todo("should keep a live cell alive when it has 2 or 3 live neighbors (survival)");
19	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
20	  it.todo("should keep a block still life unchanged: [(0,0),(1,0),(0,1),(1,1)] stays the same");
21	  it.todo("should oscillate a blinker: [(0,0),(0,1),(0,2)] becomes [(-1,1),(0,1),(1,1)]");
22	});
23

1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	const parseKey = (key: string): Cell => key.split(",").map(Number) as Cell;
5	
6	export function nextGeneration(cells: Cell[]): Cell[] {
7	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
8	  const neighborCounts = new Map<string, number>();
9	
10	  for (const [x, y] of cells) {
11	    for (let dx = -1; dx <= 1; dx++) {
12	      for (let dy = -1; dy <= 1; dy++) {
13	        if (dx === 0 && dy === 0) continue;
14	        const key = cellKey(x + dx, y + dy);
15	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
16	      }
17	    }
18	  }
19	
20	  const result: Cell[] = [];
21	  for (const [key, count] of neighborCounts) {
22	    const isAlive = liveSet.has(key);
23	    if (count === 3 || (isAlive && count === 2)) {
24	      result.push(parseKey(key));
25	    }
26	  }
27	
28	  return result;
29	}
